#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;
    int block_size = blockDim.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Bounds-checked load into shared memory
    for (int i = tid; i < cols; i += block_size) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Perform sequential scan with explicit bounds
    if (tid == 0) {
        for (int i = 1; i < cols; i++) {
            shared[i] += shared[i - 1];
        }
    }
    __syncthreads();

    // Bounds-checked store
    for (int i = tid; i < cols; i += block_size) {
        output[row * cols + i] = shared[i];
    }
}

torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim) {
    TORCH_CHECK(x.is_cuda(), "Input tensor must be on GPU");
    TORCH_CHECK(x.is_contiguous(), "Input tensor must be contiguous");
    TORCH_CHECK(dim >= 0 && dim < x.dim(), "Invalid dimension");

    auto sizes = x.sizes();
    int n = sizes[dim];
    TORCH_CHECK(n > 0, "Scan dimension must have size > 0");

    int total_elements = x.numel();
    int outer_elements = total_elements / n;

    auto x_reshaped = x.reshape({outer_elements, n}).contiguous();
    auto out = torch::zeros_like(x_reshaped);

    int threads = min(256, ((n + 31) / 32) * 32);
    int shared_mem_size = n * sizeof(float);

    TORCH_CHECK(shared_mem_size <= 49152, 
                "Shared memory requirement exceeds GPU limit for dimension size");

    row_scan_kernel<float><<<outer_elements, threads, shared_mem_size>>>(
        x_reshaped.data_ptr<float>(),
        out.data_ptr<float>(),
        outer_elements,
        n
    );

    cudaError_t err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, 
                "CUDA kernel launch failed: ", cudaGetErrorString(err));

    return out.reshape(sizes);
}
